try {
  const body = $input.first().json.body || {};
  const speech = body.SpeechResult || body.UnstableSpeechResult || body.user_message || body.speech || body.RecognitionResult || body.text || "";
  const callSid = body.CallSid || "unknown";
  const from = body.From || "unknown";
  const callStatus = body.CallStatus || "unknown";
  return [{ json: { isGreeting: speech.trim() === "" ? "true" : "false", userText: speech.trim(), call_sid: callSid, caller_number: from, call_status: callStatus, debugInfo: body } }];
} catch (error) {
  return [{ json: { isGreeting: "true", userText: "", call_sid: "error", caller_number: "error", error: error.message } }];
}

const item = $input.first()?.json || {};
const userText = item.userText ?? item.user_input ?? item.text ?? "";
const llmRaw = item.text ?? item.llm_output ?? "{}";
const callerNumber = item.caller_number || "unknown";
const callSid = item.call_sid || "unknown";

if (!userText || userText.trim() === "") {
  return { json: { classification: "Pleasetalk", user_input: "", extracted_symptoms: [], emergency_level: "none", next_action: "redirect_to_medical", caller_number: callerNumber, call_sid: callSid } };
}

let parsed;
try {
  const cleaned = llmRaw.replace(/```json/gi, "").replace(/```/g, "").trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { classification: "Pleasetalk", user_input: userText, extracted_symptoms: [], emergency_level: "none", next_action: "redirect_to_medical" };
}

return { json: { classification: parsed.classification || "Pleasetalk", user_input: parsed.user_input || userText, extracted_symptoms: Array.isArray(parsed.extracted_symptoms) ? parsed.extracted_symptoms : [], emergency_level: parsed.emergency_level || "none", next_action: parsed.next_action || "redirect_to_medical", caller_number: callerNumber, call_sid: callSid } };

const inputItems = $input.all();
return inputItems.map(item => {
  const data = item.json;
  let symptomsList;
  try { symptomsList = Array.isArray(data.extracted_symptoms) ? data.extracted_symptoms : JSON.parse(data.extracted_symptoms); } catch { symptomsList = []; }
  const symptomSummary = symptomsList.length > 0 ? symptomsList.join(", ") : "a medical emergency";
  const chatInput = `Please stay calm. You said: "${data.user_input}". This may indicate: ${symptomSummary}. Help is on the way. Please tell me your exact location.`;
  return { json: { ...data, chatInput, all_symptoms: data.all_symptoms || [] } };
});

